48	const BASE_PREMIUMS: Record<string, number> = {
49	  sword: 100,
50	  amulet: 60,
51	  staff: 80,
52	  potion: 40,
53	  rune: 25,
54	  moonstone: 25,
55	};
56	
57	const PROCESSING_FEE_G = 5;
58	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1; // 10% surcharge on policy base
59	const COMPONENT_BLOCK_SIZE = 3;
60	const COMPONENT_BLOCK_PRICE_G = 60;
61	const CURSE_SURCHARGE_RATE = 0.5; // 50% of cursed item's base premium
62	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3; // 30% of enchanted item's base premium
63	const HIGH_ENCHANTMENT_THRESHOLD = 5;
64	
65	const COMPONENT_TYPES = ["rune", "moonstone"];
66	
67	const priceForComponentGroup = (count: number, unitPrice: number): number =>
68	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE_G : count * unitPrice;
69	
70	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
71	
72	const isCursed = (item: Item): boolean => item.cursed === true;
73	const isHighlyEnchanted = (item: Item): boolean =>
74	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
75	
76	const surchargeFor = (items: Item[], predicate: (i: Item) => boolean, rate: number): number =>
77	  items.filter(predicate).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
78	
79	const LOYALTY_YEARS_THRESHOLD = 2;
80	const LOYALTY_DISCOUNT_RATE = 0.2; // 20% discount on policy base
81	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15; // 15% discount on policy base for contracts after the first
82	
83	const isLoyalCustomer = (customer: Customer): boolean =>
84	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
85	
86	const componentsBase = (items: Item[]): number =>
87	  COMPONENT_TYPES.reduce((sum, type) => {
88	    const count = items.filter((i) => i.type === type).length;
89	    return sum + priceForComponentGroup(count, BASE_PREMIUMS[type]);
90	  }, 0);
91	
92	const nonComponentsBase = (items: Item[]): number =>
93	  items.filter((i) => !isComponent(i)).reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
94	
95	const policyBaseFor = (items: Item[]): number =>
96	  componentsBase(items) + nonComponentsBase(items);
97	
98	const quotePremium = (items: Item[], customer: Customer, isFollowUpContract: boolean): number => {
99	  const policyBase = policyBaseFor(items);
100	  const curseSurcharge = surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
101	  const enchantmentSurcharge = surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
102	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
103	  const loyaltyDiscount = isLoyalCustomer(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
104	  const followUpDiscount = isFollowUpContract ? policyBase * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
105	  return Math.ceil(
106	    policyBase +
107	      curseSurcharge +
108	      enchantmentSurcharge +
109	      firstInsuranceSurcharge -
110	      loyaltyDiscount -
111	      followUpDiscount +
112	      PROCESSING_FEE_G,
113	  );
114	};
115	
116	const INSURANCE_VALUES: Record<string, number> = {
117	  sword: 1000,
118	  amulet: 600,
119	  staff: 800,
120	  potion: 400,
121	  rune: 250,
122	  moonstone: 250,
123	};
124	const DEDUCTIBLE_G = 100;
125	const CAP_MULTIPLIER = 2;
126	
127	interface PolicyState {
128	  items: Item[];
129	  remainingCap: number;
130	}
131	
132	const insuranceSumFor = (items: Item[]): number =>
133	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
134	
135	export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
136	  const policies: Record<number, PolicyState> = {};
137	  let quoteCount = 0;
138	  const results: StepResult[] = scenario.steps.map((step, index) => {
139	    if (step.op === "quote") {
140	      const premium = quotePremium(step.items, scenario.customer, quoteCount > 0);
141	      quoteCount += 1;
142	      policies[index] = {
143	        items: step.items,
144	        remainingCap: CAP_MULTIPLIER * insuranceSumFor(step.items),
145	      };
146	      return { premium };
147	    }
148	    const policy = policies[step.policy];
149	    const totalDamage = step.incident.damages.reduce((sum, d) => sum + d.amount, 0);
150	    const rawPayout = totalDamage - DEDUCTIBLE_G;
151	    const payout = Math.min(rawPayout, policy.remainingCap);
152	    policy.remainingCap -= payout;
153	    return { payout, remainingCap: policy.remainingCap };
154	  });
155	  return { results };
156	};
